<?php
namespace App\Models;use App\Models\Concerns\BelongsToWorkspace;use Illuminate\Database\Eloquent\Model;class Subscription extends Model{use BelongsToWorkspace;protected $fillable=['workspace_id','plan_id','status','trial_ends_at','current_period_start','current_period_end','billing_cycle','grace_ends_at','gateway','metadata'];protected function casts():array{return ['trial_ends_at'=>'date','current_period_start'=>'date','current_period_end'=>'date','grace_ends_at'=>'date','metadata'=>'array'];}public function plan(){return $this->belongsTo(Plan::class);}public function invoices(){return $this->hasMany(Invoice::class);}public function payments(){return $this->hasMany(Payment::class);}}
